#include <stdio.h>
#include <stdbool.h>
#define MAXN 305
int a[MAXN];
bool pal[MAXN][MAXN];
int dp[MAXN];
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        // palindrome table
        for(int i=0;i<N;i++){
            pal[i][i]=true;
            if(i+1<N) pal[i][i+1]=(a[i]==a[i+1]);
        }
        for(int len=3; len<=N; ++len){
            for(int l=0; l+len-1<N; ++l){
                int r=l+len-1;
                pal[l][r]=(a[l]==a[r]) && pal[l+1][r-1];
            }
        }
        // dp
        for(int i=0;i<N;i++){
            dp[i]=i+1; // worst case: each element alone
            for(int j=0;j<=i;j++){
                if(pal[j][i]){
                    int cand = (j>0 ? dp[j-1] : 0) + 1;
                    if(cand<dp[i]) dp[i]=cand;
                }
            }
        }
        printf("%d\n", dp[N-1]);
    }
    return 0;
}

