import sys

def solve_one(N, a):
    pal = [[False]*N for _ in range(N)]
    for i in range(N):
        pal[i][i] = True
        if i+1 < N:
            pal[i][i+1] = (a[i] == a[i+1])
    for length in range(3, N+1):
        for l in range(0, N-length+1):
            r = l + length - 1
            pal[l][r] = (a[l] == a[r]) and pal[l+1][r-1]
    dp = [N+1]*N
    for i in range(N):
        for j in range(i+1):
            if pal[j][i]:
                cand = (dp[j-1] if j>0 else 0) + 1
                if cand < dp[i]:
                    dp[i] = cand
    return dp[N-1]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    outputs = []
    for _ in range(T):
        N = int(next(it))
        a = [int(next(it)) for _ in range(N)]
        outputs.append(str(solve_one(N, a)))
    sys.stdout.write('\n'.join(outputs))

if __name__ == "__main__":
    main()

